var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"20:03 ARC-KP1\\n<color=#ff3636>두 번째 사건 발생</color> 3시간 경과","JPN":"20:03 ARC-KP1\\n<color=#ff3636>二度目の事件発生から</color>3時間経過","ENG":"20:03 ARC-KP1\\n3 hours after <color=#ff3636>2nd Incident</color>","TWN":"20:03 ARC-KP1\\n<color=#ff3636>第二波事件發生</color>後經過3小時"},"stage":{"bg":"MAINSTREAM_000008","bgm":"CUTSCENE_AIRPLANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>ARC-KP1, 도시관리국에서 알려드립니다.</color>","JPN":"<color=#ffd34c>ARC-KP1、都市管理局からお知らせします。</color>","ENG":"<color=#ffd34c>ARC-KP1, Attention, citizens. This is an announcement from City Managements</color>","TWN":"<color=#ffd34c>ARC-KP1，城市管理局通知。</color>"},"stage":{"bg":"MAINSTREAM_000008","bgm":"CUTSCENE_AIRPLANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>도시관리국은 알파트릭스 그룹의 부회장 및 계열사 대표를 살해한 혐의를 받고 있는 카운터 용의자 신지아를 수배 중입니다.</color>","JPN":"<color=#ffd34c>都市管理局はアルファトリックスグループの副会長および系列会社の代表を殺害した疑いで、\\nカウンター容疑者のヒメノ・ユイを指名手配しています。</color>","ENG":"<color=#ffd34c>City Managements and Alphatrix are looking for the murder fugitive and Counter, Shin Jia, who is accused of assassinating Alphatrix Group's Vice Chairman and a CEO of their affiliate company.</color>","TWN":"<color=#ffd34c>城市管理局針對殺害阿爾法崔克斯集團副會長和分公司代表的嫌犯 制裁者沈佳發出通緝令。</color>"},"stage":{"bg":"MAINSTREAM_000008","bgm":"CUTSCENE_AIRPLANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>현재, 도시관리국은 용의자의 검거를 위해 최선을 다하고 있으니, 시민 여러분의 적극적인 협조를…….</color>","JPN":"<color=#ffd34c>現在、都市管理局は容疑者の検挙のために最善を尽くしており、市民の皆様の積極的なご協力を……</color>","ENG":"<color=#ffd34c>Currently, City Managements is working hard to find and apprehend this suspect and would appreciate any assistance from citizens.</color>","TWN":"<color=#ffd34c>城市管理局會盡速將嫌犯逮捕歸案，請市民們積極提供協助……</color>"},"stage":{"bg":"MAINSTREAM_000008","bgm":"CUTSCENE_AIRPLANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"이, 일이 엄청 커졌구나, 지아야.","JPN":"あの、ユイちゃん。事が大きくなってきたわ。","ENG":"Looks like things are getting out of hand, Jia.","TWN":"小佳…事情現在鬧很大欸！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"도시관리국까지 개입하고 말았으니……. 이를 어쩐다…….","JPN":"都市管理局まで介入してきて……どうすれば……","ENG":"Now with City Managements involved... This isn’t looking good at all...","TWN":"現在連城市管理局都開始介入……怎麼辦……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"아뇨. 덕분에 범인이 누구인지 알 것 같아요.","JPN":"いいえ。おかげで犯人が誰なのかわかりそうです。","ENG":"No, but I think I know who we should be looking for.","TWN":"不擔心，托他們的福，我好像知道誰才是真兇了。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"실행범이 아니라 배후에 있는 인물이지만요.","JPN":"実行犯ではなく、背後にいる人物のことですが。","ENG":"It may not be the person who committed the murders, but it should be the person behind everything.","TWN":"應該說是幕後的主使者才對。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"뭐라고? 그럼 여기서 꾸물거릴 필요도 없지 않느냐?","JPN":"本当？　じゃあ、ここで時間を持て余す必要もないんじゃないの？","ENG":"What? Then what are we waiting for?","TWN":"真的嗎？那我們還在這裡浪費時間幹嘛？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"당장 가서 그 못된 놈을…….","JPN":"今すぐその悪党を……","ENG":"Let’s head over there right now and...!","TWN":"立刻去找那個壞蛋……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"안 돼요. 실행범이 다음 타겟을 노리고 있을 테니까요.","JPN":"いけません。実行犯が次のターゲットを狙っているはずです。","ENG":"We can’t. Because the murderer is after their next target right now.","TWN":"還不可以，真凶現在應該正準備對下一個目標下手。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"다음 타겟? 다음 타겟이 누군지 어떻게 알고?","JPN":"次のターゲット？　次のターゲットが誰なのかわかってるの？","ENG":"Next target? And you know who that is?","TWN":"下一個目標？ 那你怎麼知道下一個目標是誰？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"네? 세실리아 씨, 누군지 모르시겠어요? 제가 이해하기 쉽게 가르쳐 드릴까요?","JPN":"セシリアさんは誰なのかわかりませんか？　わかりやすく教えましょうか？","ENG":"Huh? You don’t know, Cecilia? Should I give you a simple run down?","TWN":"嗯？你不知道嗎？需要我告訴你嗎？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"아, 아니다! 알지! 알다마다!","JPN":"い、いや！　わかる！　もちろんわかるわよ！","ENG":"Th-that’s not necessary! O-of course I know!","TWN":"不…不用！我知道啦！怎麼可能不知道！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"역시 그러실 줄 알았어요.","JPN":"やっぱりそうだと思いました。","ENG":"I had a feeling that you did.","TWN":"我就知道你知道。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"하지만 남은 두 회사는 일렉트로닉스와 헤비암즈……. 한 군데씩 찾아가기에는 시간이 부족해요.","JPN":"しかし、残る2つの会社、エレクトロニクスとヘビーアームズ……\\n一ヶ所ずつ向かうには時間が足りません。","ENG":"There are Electronics and Heavyarms left. But we don’t have enough time to visit them one at a time.","TWN":"不過我們還有電子和重武裝這兩個地方要去……一起行動的話時間會來不及。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"마음은 알겠지만 지아야, 나는 너처럼 힘센 카운터가 아니란다.","JPN":"ユイちゃん、気持ちはわかるけど、私は君みたいな強いカウンターじゃないの。","ENG":"I understand your frustration, Jia. But I’m not a Counter like you.","TWN":"我懂你的意思，小佳。但我又不像你是很厲害的制裁者！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"도시경비대가 사방에 쫙 깔렸을 텐데 나 혼자 어떻게 가겠니?","JPN":"都市警備隊があちこちを監視しているのに、私一人で向かうのは厳しいでしょう？","ENG":"There will be guards all throughout the city, and I won’t be able to sneak pass them alone.","TWN":"城市守衛現在一定設下天羅地網，我一個人要怎麼去啦！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그렇네요……. 혼자 가시면 위험할 텐데 이를 어쩌죠?","JPN":"そうですね……一人で動くのは危ないですが、どうしましょう。","ENG":"You're right... It’s far too dangerous to go alone. What should we do?","TWN":"說的也是……你一個人去的話可能會有危險，怎麼辦呢？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"subtitle","speaker":null,"text":{"KOREA":"21:02 ARC-KP1\\n헤비암즈 군수 공장, 인근 무역항\\n<color=#ff3636>두 번째 사건 발생</color> 4시간 경과","JPN":"21:02 ARC-KP1\\nヘビーアームズ軍需工場、付近の貿易港\\n<color=#ff3636>二度目の事件発生から</color>4時間経過","ENG":"21:02 ARC-KP1\\nHeavyarms Munitions Factory, near Trading Port\\n4 hours after <color=#ff3636>2nd Incident</color>","TWN":"21:02 ARC-KP1\\n重武裝工廠附近港口\\n<color=#ff3636>第二波事件發生</color>後經過4小時"},"stage":{"bg":"WAREHOUSE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WAREHOUSE_02","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L40_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"흐음……. 용의자가 나타날 기미는 안 보이네요.","JPN":"うーん、容疑者が現れる気配はないですね。","ENG":"Hmm... The suspect is nowhere in sight.","TWN":"嗯……怎麼感覺嫌犯不會現身？"},"stage":{"bg":"WAREHOUSE_02","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"후후, 역시 잠복근무 중에는 간식이 낙이죠. 경정님도 빵 하나 드실래요?","JPN":"ふふ、張り込み中はやっぱりおやつが楽しみですよね。\\n警視様もパンを食べませんか？","ENG":"He he. Eating snacks is the best during a stakeout. Major, do you want some bread too?","TWN":"嘿嘿，埋伏的時候當然要吃零食囉～警政大人，你要來一點嗎？"},"stage":{"bg":"WAREHOUSE_02","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L44_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"빵? 그럼 난 초코 소보루로…….","JPN":"パン？　じゃあ、チョコデニッシュで……","ENG":"Bread? Then I’ll have a chocolate streusel...","TWN":"麵包？ 那我要巧克力波蘿麵……"},"stage":{"bg":"WAREHOUSE_02","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L45_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"아, 아니. 필요없어. 경위나 먹도록 해.","JPN":"い、いや。いらないわ。一人で食べて。","ENG":"N-nevermind. Thank you for offering still.","TWN":"不…我不用，警衛你自己吃吧。"},"stage":{"bg":"WAREHOUSE_02","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L46_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"아까부터 왜 그러세요? 알파트릭스 쪽이랑 만날 때부터 상한 우유 마신 표정이시던데?","JPN":"さっきからどうしたんですか？\\nアルファトリックスの方々と会ってから、腐った牛乳でも飲んだ顔をしていますよ？","ENG":"What’s wrong? You keep making that sour face whenever we run into someone from Alphatrix.","TWN":"你幹嘛這樣？從剛剛在阿爾法崔克斯的時候，你就一直一副喝到臭酸牛奶的表情。"},"stage":{"bg":"WAREHOUSE_02","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"읏, 알고 있었어?","JPN":"うっ、気づいてたの？","ENG":"Ngh... Is it that obvious?","TWN":"喔？你有發現喔？"},"stage":{"bg":"WAREHOUSE_02","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"이사진들도 다 알아챘을 걸요. 경정님은 말로는 아니라고 해도 얼굴이 솔직하시거든요.","JPN":"理事の方々もみんな気づいていたと思いますよ。\\n警視様は言葉では否定しても、顔が正直ですから。","ENG":"I’m sure even all the directors already noticed. The expression on your face says everything you want to say, Major.","TWN":"董事會的人也有發現吧？你的心情全寫在臉上。"},"stage":{"bg":"WAREHOUSE_02","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"……마음에 안 들어서 그래.","JPN":"……気に食わないからよ。","ENG":"It’s because I don’t like them.","TWN":"……因為我不喜歡這樣。"},"stage":{"bg":"WAREHOUSE_02","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"자기들끼리 수습하려다가 일이 커질 것 같으니까 신고를 한다고?","JPN":"自分たちだけで収拾しようとしたくせに、\\n事が大きくなりそうだから警察に通報するって？","ENG":"They tried to cover it up, but since it’s gotten out of control, now they want our help?","TWN":"自己沒辦法收拾，結果事情鬧大才來報警！"},"stage":{"bg":"WAREHOUSE_02","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"탈세에 독점에 온갖 횡포는 다 부리고, 저래서야 범죄 조직이랑 뭐가 달라?","JPN":"脱税に独占と、ありとあらゆる横暴を働いたくせに、\\nあれじゃあ犯罪組織と何が違うの？","ENG":"After all the tax evasions and tyranny of unfair competition, how are they different from organized crime?","TWN":"他們自己還不是逃漏稅、壟斷市場，各種壞事幹盡，和犯罪組織有什麼兩樣？"},"stage":{"bg":"WAREHOUSE_02","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"하하, 알파트릭스가 국제적으로 원한 살 짓을 많이 하긴 했죠.","JPN":"ハハ、確かにアルファトリックスは国際的に恨みをたくさん買っていますからね。","ENG":"Haha. Alphatrix did put a target on their backs internationally.","TWN":"哈哈，阿爾法崔克斯在國際上的確是做過許多見不得人的事。"},"stage":{"bg":"WAREHOUSE_02","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L6_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그래도 신고가 들어왔으니 어쩌겠어요. 이미 희생자가 둘이나 나왔고요.","JPN":"でも通報が入った以上仕方ありません。すでに犠牲者が2人も出ましたし。","ENG":"But still, they are asking for our help. Plus, two victims have already turned up.","TWN":"不過既然人家報警，我們也只能受理囉～而且現在已經出現兩名受害者咧！"},"stage":{"bg":"WAREHOUSE_02","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"흥…….","JPN":"ふーん……","ENG":"Hmpf.","TWN":"哼……"},"stage":{"bg":"WAREHOUSE_02","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그래서 경위는 어떻게 생각해? 그 신지아란 사람이 정말 범인일까?","JPN":"で、警部補はどう思う？　あのヒメノ・ユイという人が本当に犯人だと思う？","ENG":"Anyway, what do you think about this, Lieutenant? You really think Shin Jia is the perp we’re looking for?","TWN":"那你怎麼說？你認為那個叫沈佳的人真的是犯人嗎？"},"stage":{"bg":"WAREHOUSE_02","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"글쎄요…….","JPN":"どうでしょうね……","ENG":"I don't know.","TWN":"這個嘛……"},"stage":{"bg":"WAREHOUSE_02","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그라운드 원에서 잠시 마주친 적이 있었는데, 그럴 만한 사람 같지는 않았어요.","JPN":"グラウンド・ワンで少しだけ会ったことがありますが、\\nそんなことをするような人には見えませんでしたよ。","ENG":"I met her once at Ground One, but she didn’t look like the type to murder anyone.","TWN":"我在G1有短暫和她見過面，她感覺不像殺人犯。"},"stage":{"bg":"WAREHOUSE_02","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"뭐, 자세한 이야기는 서에서 하면 되지 않을까요?","JPN":"まあ、詳しい話は署で聞くとしましょう。","ENG":"Well, we’ll know the truth once we get her in for questioning.","TWN":"細節等回到署裡後再說吧？"},"stage":{"bg":"WAREHOUSE_02","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"……방금 컨테이너 사이로 얼핏 보인 그림자, 여자 두 명이었어.","JPN":"……今コンテナの間からちらっと見えた影、女性2人だった。","ENG":"...I saw two shadowy figures, both female, walking between the containers.","TWN":"……我剛看到有兩個人影從貨櫃中間晃過去！"},"stage":{"bg":"WAREHOUSE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"잘 보셨어요. 경정님도 눈썰미가 나날이 좋아지시네요.","JPN":"よく気づきました。警視様の観察力も日々成長していますね。","ENG":"Good catch. Your eyesight seems to get better each day.","TWN":"好眼力！警政大人的視力真是越來越好呢！"},"stage":{"bg":"WAREHOUSE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"자, 그럼 차 시동 걸겠습니다~","JPN":"それじゃあ、エンジンをかけますねー。","ENG":"Okay, I’ll start the car!","TWN":"出發吧！我來開車～"},"stage":{"bg":"WAREHOUSE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"지아야, 사람도 없는데 이렇게 살금살금 다녀야겠니?","JPN":"ユイ、周りに誰もいないのに、ここまでこっそり移動する必要ってあるの？","ENG":"Jia, do we really have to tiptoe even though no one is around?","TWN":"小佳，這邊又沒有人，有需要這樣躡手躡腳的嗎？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"네. 도시관리국이 나섰으니 이제 마주치는 분들은 모두 조심해야 돼요.","JPN":"はい。都市管理局が介入してきた以上、\\nこれから出会う人は全員警戒しなければなりません。","ENG":"Yes. We must be careful not to run into anyone.","TWN":"是的，城市管理局介入後，現在的行動必須更謹慎。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"으음, 말하자마자 들킨 것 같지만요.","JPN":"うーん、言ったとたんにバレてしまったようです。","ENG":"Um... I think we just got caught.","TWN":"嗯，不過在說話的同時，似乎已經被發現了。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"드, 들켰다고?!","JPN":"バ、バレたの！？","ENG":"W-what?!","TWN":"被…被發現了嗎？！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"속도 줄이라고 몇 번을 말해야 돼, 강소영 경위?!","JPN":"スピードを落とせって何回言わせれば気が済むの！　マエカワ警部補！！","ENG":"How many times do I have to tell you to slow down, Lieutenant?!","TWN":"姜素英警衛，跟你說了多少次，開慢一點！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L34_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"아하하, 오랜만에 운전대를 잡아서 그런지 저도 모르게 밟았나 보네요.","JPN":"あはは、久しぶりにハンドルを握ったからか、ついスピードを出してしまいました。","ENG":"Ahaha...! I guess racer blood runs through my veins.","TWN":"哈哈哈，可能是太久沒握方向盤，不自覺就一直踩油門～"},"stage":{"bg":"DOCK_CLOUDY","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L35_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그래도 다친 사람은 없으니까 오케이 아닐까요?","JPN":"でも怪我人もいないし、結果オーライですよね？","ENG":"But no one got hurt, so everything’s a-okay!","TWN":"不過應該OK吧？反正沒人受傷嘛～"},"stage":{"bg":"DOCK_CLOUDY","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L37_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"오케이는 무슨?! 이쪽은 까딱 잘못했으면 차에 치일 뻔했단 말이다!","JPN":"オーライじゃないわ！！　こっちは間一髪で車に轢かれるところだったのよ！","ENG":"A-okay?! We almost crashed!!","TWN":"OK什麼？！差點就要撞到我們咧！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"괜찮아요, 세실리아 씨. 여긴 도로가 아니라 항구잖아요?","JPN":"大丈夫ですよ、セシリアさん。ここは道路じゃなくて港でしょう？？","ENG":"It’s okay, Cecilia. We’re at the harbor and not the road.","TWN":"沒事啦，賽希莉亞。畢竟這裡是港口，不是一般的道路。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"뭔 뚱딴지 같은 소리냐, 그게?!","JPN":"何を突拍子もないことを言ってるの！？","ENG":"How’s that supposed to help?!","TWN":"你在說什麼傻話？！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그쪽은……. 그라운드 원에서 뵀던 경찰 언니시군요.","JPN":"そちらは……グラウンド・ワンでお会いした警察の方ですね。","ENG":"You’re... the police officer I met at Ground One.","TWN":"你……不是我在G1見過的警察姐姐嗎？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"네. 이런 일로 다시 만나게 될 줄은 몰랐네요, 신지아 대표님.","JPN":"ええ。このような形で再会するとは思いませんでした、ヒメノ・ユイ代表。","ENG":"Yes. I didn’t expect to see you again like this, Ms. Shin Jia.","TWN":"是的，沒想到會以這種形式再次見面，沈佳代表。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"우리와 잠시 경찰서까지 동행해 줘야겠어요.","JPN":"警察署までご同行願います。","ENG":"We need you to come to the station with us.","TWN":"請你和我們到局裡一趟，"},"stage":{"bg":"DOCK_CLOUDY","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"사건 해결을 위해서입니다. 저항하지 말아 줬으면 좋겠네요.","JPN":"事件解決のためです。抵抗はしないでください。","ENG":"It’s to solve this case. Please do not try to resist.","TWN":"協助警方釐清案情，請你配合一下！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L50_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"사건 해결이라고요?","JPN":"事件解決ですって？","ENG":"To solve this case?","TWN":"釐清案情？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"지아야, 저들을 따라갔다가 다음 타겟이 당하기라도 하면 어떡하려고!","JPN":"ユイちゃん、あの人たちに時間を取られている間に、\\n次のターゲットがやられるかもしれない！","ENG":"Jia, if we follow them, we won’t be able to save the murderer’s next target!","TWN":"小佳，你跟他們去之後，萬一下一個目標遇害的話怎麼辦！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"범행을 막은 다음에 설명해도 충분하지 않겠니?","JPN":"犯行を防いだ後に説明してもいいんじゃない？","ENG":"Don’t you think we’ll still have time after we stop another murder from happening?","TWN":"等你阻止犯人後再去解釋也不遲吧？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"사건을 해결하려는 건 저희도 마찬가지예요. 경찰 여러분.","JPN":"事件を解決しようとしているのはこちらも同じです、警察の皆さん。","ENG":"Officers, we too are trying to solve this case.","TWN":"二位警察，我們也想釐清案情，"},"stage":{"bg":"DOCK_CLOUDY","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그러니까…… 죄송하지만 그 제안은 받아들일 수 없어요!","JPN":"ですので……申し訳ありませんが、その提案は受け入れられません！","ENG":"So... I'm sorry, but I won’t be able to accompany you this time!","TWN":"所以……很抱歉，恕我無法配合！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"유감이네요. 저희는 민중의 지팡이답게 도와드리려는 건데요.","JPN":"それは残念です。\\n私たちは市民の味方として助けようとしているだけなのですが。","ENG":"I’m sorry to hear that. We just wanted to help as the protector of the people.","TWN":"真是令人遺憾！身為人民的保母，我們是希望能幫助你。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"……할아버님께서 말씀하셨어요.","JPN":"……お祖父様はこうおっしゃいました。","ENG":"...Grandfather said...","TWN":"……我爺爺有說，"},"stage":{"bg":"DOCK_CLOUDY","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"도움을 거절하는 사람의 의사를 무시하고 도와 주는 건 무례한 짓이라고요.","JPN":"助けを断る人の意思を無視して、それでも助けようとすることは無礼なことだと。","ENG":"That it’s rude to help someone who doesn’t want your help.","TWN":"無視對方的意願，強加在對方身上的好意，是有失禮貌的。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"계속 그러시면 저도 어쩔 수 없어요. 경찰 여러분이 무례한 분들이 되는 건 싫으니까요!","JPN":"諦めてくれないなら私もこうするしかありません。\\n警察の皆さんには無礼な人になってほしくないので！","ENG":"But if you keep pushing, I’ll have to resort to other measures. Because I don't want you to become disrespectful!","TWN":"你們再這樣的話，我也只好出手。因為我不希望你們變成有失禮貌的人！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};